plugin.detectCode:
const lines = input.trim().split('\n').filter(l => l.trim() && !l.trim().startsWith('#'));
const keyVal = lines.filter(l => /^[A-Z_][A-Z0-9_]*\s*=/i.test(l)).length;
return lines.length > 0 && keyVal / lines.length > 0.5 ? 0.95 : 0;

plugin.executeCode:
const SECRET_PATTERNS = /secret|password|passwd|pwd|token|api[_-]?key|private[_-]?key|auth|credential|access[_-]?key|signing[_-]?key/i;
const lines = input.split('\n');
const vars = [];
let commentCount = 0;
for (const raw of lines) {
  const line = raw.trim();
  if (!line) continue;
  if (line.startsWith('#')) { commentCount++; continue; }
  const m = line.match(/^([^=]+)=(.*)$/);
  if (!m) continue;
  const key = m[1].trim();
  const val = m[2].trim();
  const isEmpty = val === '';
  const isSecret = SECRET_PATTERNS.test(key);
  vars.push({ key, val, isEmpty, isSecret });
}
const total = vars.length;
const emptyCount = vars.filter(v => v.isEmpty).length;
const secretCount = vars.filter(v => v.isSecret).length;
const header = [
  `.env Inspector`,
  `  Total variables: ${total}`,
  `  Empty values:    ${emptyCount}`,
  `  Secrets redacted: ${secretCount}`,
  `  Comment lines:   ${commentCount}`,
  '',
  `${'KEY'.padEnd(35)} VALUE`,
  '-'.repeat(70),
];
const rows = vars.map(v => {
  let display = v.val;
  if (v.isSecret && v.val) display = '[REDACTED]';
  else if (v.isEmpty) display = '(empty)';
  const flag = v.isEmpty ? ' ⚠ EMPTY' : v.isSecret ? ' 🔒 SECRET' : '';
  return v.key.padEnd(35) + ' ' + display + flag;
});
return { output: [...header, ...rows].join('\n'), outputLanguage: 'text' };
